export const 入山符乙二 = (bi) => {
    const u = bi.u;
    const k = 1.1;
    const X = (c) => (c - 12) * k;
    const Z = (r) => (r - 1.0) * k;
    const 線 = (書, 寬 = 0.55) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.55) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    // ── 左冖冠 ──
    線(p => p.M(X(6.3), Z(2.6)).L(X(10.9), Z(2.3)), 0.6);
    出(p => p.M(X(6.3), Z(2.65)).C(X(6.0), Z(3.3), X(5.8), Z(3.9), X(5.6), Z(4.5)));
    出(p => p.M(X(10.9), Z(2.35)).C(X(11.1), Z(3.0), X(11.2), Z(3.7), X(11.3), Z(4.3)));
    線(p => p.M(X(6.6), Z(3.25)).L(X(10.7), Z(3.05)), 0.48);
    線(p => p.M(X(6.7), Z(3.95)).L(X(10.6), Z(3.75)), 0.48);
    // 左冠垂巛三尾（左尾綴環）
    出(p => p.M(X(7.0), Z(4.4)).C(X(6.5), Z(5.8), X(7.2), Z(7.2), X(6.7), Z(8.6))
        .C(X(6.5), Z(9.1), X(6.5), Z(9.4), X(6.6), Z(9.6)));
    bi.ctx.save();
    bi.ctx.lineWidth = 0.4 * u;
    bi.A(X(6.6), Z(10.0), 0.45 * k);
    bi.ctx.restore();
    出(p => p.M(X(8.3), Z(4.5)).C(X(7.9), Z(6.0), X(8.7), Z(7.5), X(8.3), Z(9.0)));
    出(p => p.M(X(9.7), Z(4.4)).C(X(9.3), Z(5.9), X(10.1), Z(7.3), X(9.7), Z(8.8)));
    // ── 右冖冠 ──
    線(p => p.M(X(12.6), Z(2.4)).L(X(17.2), Z(2.1)), 0.6);
    出(p => p.M(X(12.6), Z(2.45)).C(X(12.4), Z(3.0), X(12.3), Z(3.6), X(12.2), Z(4.1)));
    出(p => p.M(X(17.2), Z(2.15)).C(X(17.4), Z(2.8), X(17.5), Z(3.4), X(17.6), Z(4.0)));
    線(p => p.M(X(12.9), Z(3.0)).L(X(17.0), Z(2.8)), 0.48);
    線(p => p.M(X(13.0), Z(3.65)).L(X(16.9), Z(3.45)), 0.48);
    // 右冠垂乙曲鏈二道
    出(p => p.M(X(13.2), Z(4.4)).C(X(12.6), Z(5.2), X(12.8), Z(6.0), X(13.8), Z(6.1))
        .C(X(14.5), Z(6.2), X(14.6), Z(5.5), X(14.0), Z(5.3))
        .C(X(13.2), Z(6.6), X(13.4), Z(7.8), X(13.9), Z(8.7)));
    出(p => p.M(X(15.9), Z(4.3)).C(X(15.3), Z(5.3), X(15.5), Z(6.3), X(16.4), Z(6.5))
        .C(X(17.0), Z(6.6), X(17.1), Z(5.9), X(16.6), Z(5.7))
        .C(X(15.9), Z(7.1), X(16.1), Z(8.3), X(16.8), Z(9.3)));
    // ── 疊帶四折（蛇行連桁） ──
    出(p => p.M(X(7.2), Z(10.5))
        .L(X(16.8), Z(10.2))
        .C(X(17.9), Z(10.2), X(17.9), Z(11.6), X(16.9), Z(11.65))
        .L(X(7.5), Z(11.9))
        .C(X(6.5), Z(11.95), X(6.5), Z(13.2), X(7.5), Z(13.2))
        .L(X(16.9), Z(12.95))
        .C(X(17.9), Z(12.95), X(17.9), Z(14.3), X(16.9), Z(14.35))
        .L(X(6.9), Z(14.6)), 0.6);
    // ── 大弧下曳入∞蛇曲 ──
    出(p => p.M(X(17.3), Z(14.9))
        .C(X(13.5), Z(16.3), X(9.3), Z(16.6), X(7.2), Z(17.4))
        .C(X(5.9), Z(18.0), X(6.0), Z(19.7), X(7.6), Z(20.2))
        .C(X(9.8), Z(20.9), X(12.2), Z(21.4), X(14.3), Z(22.0))
        .C(X(16.6), Z(22.7), X(17.6), Z(21.0), X(15.9), Z(19.8))
        .C(X(14.2), Z(18.6), X(11.6), Z(19.0), X(10.0), Z(20.4))
        .C(X(8.2), Z(21.9), X(7.2), Z(23.2), X(7.8), Z(24.2)), 0.6);
    // ── 底波桁垂三尾 ──
    線(p => p.M(X(6.8), Z(25.3)).C(X(9.5), Z(24.6), X(13.0), Z(24.9), X(15.0), Z(24.9))
        .C(X(16.6), Z(24.9), X(17.5), Z(24.4), X(18.1), Z(23.6)), 0.6);
    出(p => p.M(X(7.6), Z(25.6)).C(X(7.2), Z(26.9), X(8.0), Z(28.2), X(7.5), Z(29.5)));
    出(p => p.M(X(10.4), Z(25.7)).C(X(10.0), Z(27.1), X(10.8), Z(28.5), X(10.3), Z(29.9)));
    出(p => p.M(X(14.6), Z(25.6)).C(X(14.2), Z(26.8), X(15.0), Z(27.9), X(14.5), Z(28.9)));
};
